import gzip

from transport.decoder import decode_body
from transport.encoder import encode_body


def test_emitted_gzip_is_readable_by_the_standard_library():
    body = b"outbound interoperability"
    assert gzip.decompress(encode_body(body)["body"]) == body


def test_standard_gzip_is_readable_by_the_transport_decoder():
    body = b"inbound interoperability"
    message = {
        "content_encoding": "gzip",
        "body": gzip.compress(body, mtime=0),
    }
    assert decode_body(message) == body
